# ANTI-PATTERN: Unguarded reactive execution
class BatsmanAgent:
    def play_delivery(self, ball_data):
        # Immediately calls tool without planning
        shot_type = self.llm.invoke(
            f"I see a {ball_data['speed']} kmph {ball_data['line']} ball. What shot?"
        )
        # HIGH RISK: hallucinated shots, no validation, cascading errors
        return self.execute_shot(shot_type)

# BEST PRACTICE: Deliberative with checkpoints
class StrategicBatsmanAgent:
    def play_delivery(self, ball_data):
        # Step 1: Plan phase
        plan = self.planner.invoke(
            prompt=f"Context: {self.match_state}. Delivery: {ball_data}.",
            tools=["assess_risk", "check_field", "evaluate_shots"]
        )

        # Step 2: Validate plan before execution
        if not self.validate_shot_safety(plan.recommended_shot, ball_data):
            plan.recommended_shot = "defend"  # Fallback

        # Step 3: Execute with monitoring
        result = self.execute_shot(
            plan.recommended_shot,
            confidence_threshold=0.75
        )

        # Step 4: Learn from outcome
        self.memory.add_outcome({
            "delivery": ball_data,
            "decision": plan,
            "result": result,
            "timestamp": time.time()
        })
        return result
